Here's the result of running `cat -n` on a snippet of server/websocket.ts
     1→import { WebSocketServer, WebSocket } from "ws";
     2→import type { Server } from "node:http";
     3→import { verifyToken } from "../lib/jwt";
     4→
     5→let wss: WebSocketServer | null = null;
     6→
     7→const userSockets = new Map<string, Set<WebSocket>>();
     8→
     9→export function setupWebSocket(httpServer: Server): void {
    10→  wss = new WebSocketServer({ server: httpServer, path: "/ws" });
    11→
    12→  wss.on("connection", (ws) => {
    13→    let userId: string | null = null;
    14→
    15→    ws.on("message", (raw) => {
    16→      try {
    17→        const msg = JSON.parse(raw.toString());
    18→        if (msg.type === "auth" && msg.token) {
    19→          const payload = verifyToken(msg.token);
    20→          const newUserId = payload.userId;
    21→
    22→          // Remove from old user set before associating with new one
    23→          if (userId && userId !== newUserId) {
    24→            const oldSockets = userSockets.get(userId);
    25→            if (oldSockets) {
    26→              oldSockets.delete(ws);
    27→              if (oldSockets.size === 0) userSockets.delete(userId);
    28→            }
    29→          }
    30→
    31→          userId = newUserId;
    32→          if (!userSockets.has(userId)) {
    33→            userSockets.set(userId, new Set());
    34→          }
    35→          userSockets.get(userId)!.add(ws);
    36→          ws.send(JSON.stringify({ event: "auth-ok", userId }));
    37→        } else if (msg.type === "deauth") {
    38→          // Client is logging out — remove this socket from user targeting immediately
    39→          if (userId) {
    40→            const sockets = userSockets.get(userId);
    41→            if (sockets) {
    42→              sockets.delete(ws);
    43→              if (sockets.size === 0) userSockets.delete(userId);
    44→            }
    45→            userId = null;
    46→          }
    47→        }
    48→      } catch (_) {
    49→        // Invalid token or malformed message — ignore silently
    50→      }
    51→    });
    52→
    53→    ws.on("error", () => {});
    54→
    55→    ws.on("close", () => {
    56→      if (userId) {
    57→        const sockets = userSockets.get(userId);
    58→        if (sockets) {
    59→          sockets.delete(ws);
    60→          if (sockets.size === 0) {
    61→            userSockets.delete(userId);
    62→          }
    63→        }
    64→      }
    65→    });
    66→  });
    67→
    68→  console.log("[WS] WebSocket server attached on /ws");
    69→}
    70→
    71→export function broadcast(event: string, data?: unknown): void {
    72→  if (!wss) return;
    73→  const message = JSON.stringify({ event, data, timestamp: Date.now() });
    74→  wss.clients.forEach((client) => {
    75→    if (client.readyState === WebSocket.OPEN) {
    76→      client.send(message);
    77→    }
    78→  });
    79→}
    80→
    81→export function sendToUser(userId: string, event: string, data?: unknown): void {
    82→  const sockets = userSockets.get(userId);
    83→  if (!sockets) return;
    84→  const message = JSON.stringify({ event, data, timestamp: Date.now() });
    85→  sockets.forEach((ws) => {
    86→    if (ws.readyState === WebSocket.OPEN) {
    87→      ws.send(message);
    88→    }
    89→  });
    90→}
